  st.set_page_config(
    page_title="RepoQuest",
    layout="wide",
  )
  render_ui_styles()

  # Header
  render_hero()

  # Sidebar
  with st.sidebar:
    render_mini_label("Workspace", "overview", "slate")
    if "snapshot" in st.session_state:
      current_snapshot = st.session_state["snapshot"]
      st.success(f"Analyzing: {current_snapshot.source_name}")
      st.caption(f"{current_snapshot.total_files_scanned} files scanned from {current_snapshot.total_files_seen} seen")
      if st.session_state.get("source_type") == "upload":
        st.caption("Source: uploaded ZIP")
      elif st.session_state.get("source_type") == "demo":
        st.caption("Source: bundled demo")
