      # Show analysis timestamp
      from datetime import datetime
      try:
        ts = datetime.fromisoformat(workspace.source_metadata.timestamp.replace('Z', '+00:00'))
        st.caption(f"Analyzed: {ts.strftime('%Y-%m-%d %H:%M UTC')}")
